UPDATE public.garden_import_queue SET payload = '{"species": "Tarragon", "species_slug": "tarragon", "varieties": [{"name": "Mexican Tarragon (Standard)", "slug": "mexican-tarragon-standard", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico and Central America, traditional cultivation since Aztec times (pre-1500s)", "traits": "Bushy perennial herb, 60-90cm tall, 30-45cm wide. Bright green, narrow, oblong leaves (7.5cm long). Golden-yellow, five-petaled marigold-like flowers in clusters, blooming profusely late summer to autumn.", "flesh_fruit": "", "yield_notes": "High productivity. Continuous harvest spring through autumn. Can produce year-round in frost-free Brisbane winters.", "growing_notes": "", "availability": "The Seed Collection (Australia-wide delivery including QLD), available as seeds. Quality Plants & Seedlings (express delivery to QLD). Plantmark Wholesale Nursery. Can be grown from seed sown after last frost or started indoors.", "sort_order": 0}, {"name": "Mexican Mint Marigold", "slug": "mexican-mint-marigold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Same as Mexican Tarragon (alternative common name)", "traits": "Identical to Mexican Tarragon. Upright growth habit, can reach up to 36 inches (90cm) in warm climates with woody stems.", "flesh_fruit": "", "yield_notes": "Excellent continuous production.", "growing_notes": "", "availability": "Same suppliers as Mexican Tarragon (same plant, different name).", "sort_order": 1}, {"name": "Texas Tarragon / Winter Tarragon", "slug": "texas-tarragon-winter-tarragon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Southwestern United States and Mexico", "traits": "Regional name for Mexican Tarragon. Dark green, narrow leaves with slight shine. Grows 60-91cm tall.", "flesh_fruit": "", "yield_notes": "Very productive, year-round in mild winters.", "growing_notes": "", "availability": "Australian seed suppliers including The Seed Collection.", "sort_order": 2}, {"name": "French Tarragon (True)", "slug": "french-tarragon-true", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Southern Europe and Central Asia, cultivated since medieval times (1200s-1300s). In English gardens since 16th century. Brought to America by colonists. Thomas Jefferson grew it at Monticello.", "traits": "Herbaceous perennial, 40-60cm tall (can reach 120-150cm). Slender branches, narrow lanceolate grey-green leaves (2-8cm long, 2-10mm wide). Rarely flowers; small greenish-yellow sterile flowers when present. Spreads via rhizomes.", "flesh_fruit": "", "yield_notes": "Moderate. Best harvested spring and early summer in Brisbane. Dies back in heat.", "growing_notes": "", "availability": "Mudbrick Herb Cottage (organic, ships to QLD). White House Nursery (ships to QLD). Quality Plants & Seedlings (express delivery to QLD). Allrareherbs (online). Must be purchased as live plants or cuttings, never seeds.", "sort_order": 3}, {"name": "Russian Tarragon", "slug": "russian-tarragon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Siberia, Central Asia, Eastern Europe", "traits": "Vigorous perennial, grows over 1 meter tall. Coarser, thicker leaves than French variety. Produces flowers and viable seeds (unlike French).", "flesh_fruit": "", "yield_notes": "Very high, but poor flavor quality.", "growing_notes": "", "availability": "The Seed Collection (seeds - but not recommended for purchase). Any commercial ''tarragon seeds'' are Russian tarragon.", "sort_order": 4}, {"name": "Mexican Tarragon (Tropical Strain)", "slug": "mexican-tarragon-tropical-strain", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Native to tropical Mexico, Guatemala, and Central America", "traits": "Tropical perennial herb, 60-90cm tall (can reach 1m in optimal tropical conditions). Bushy, branching growth. Narrow, shiny medium-green leaves. Abundant golden-yellow flowers.", "flesh_fruit": "", "yield_notes": "Excellent year-round production in Kerala''s tropical climate. Continuous harvest possible.", "growing_notes": "", "availability": "GardenGuru.in (Kerala delivery), Ugaoo (all-India delivery including Kerala), GreenMyLife (ships to Kerala), PlantsBazar.com (India-wide), local Kerala nurseries. Available as seeds or plants.", "sort_order": 0}, {"name": "Yerba Anís / Pericón", "slug": "yerba-an-s-peric-n", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Traditional Mexican and Central American herb, same species as Mexican Tarragon", "traits": "Traditional strain used medicinally and in cooking. Identical botanical characteristics to Mexican Tarragon.", "flesh_fruit": "", "yield_notes": "Productive year-round in tropical conditions.", "growing_notes": "", "availability": "GreenMyLife (Kerala delivery), specialty herb suppliers in India.", "sort_order": 1}, {"name": "Sweet Mace / Mexican Marigold", "slug": "sweet-mace-mexican-marigold", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Siberia, Central Asia, Eastern Europe", "traits": "Temperate climate herb requiring cool winters and dry summers.", "flesh_fruit": "", "yield_notes": "High leaf and flower production.", "growing_notes": "", "availability": "Seeds available in India (Ugaoo, GardenGuru, PlantsBazar) but not recommended for purchase.", "sort_order": 2}], "variety_count": 8}'::jsonb,
  variety_count = 8, status = 'parsed'
WHERE source_path = 'brainstorm-inbox/import-payloads/tarragon.json';

UPDATE public.garden_import_queue SET payload = '{"species": "Tea Tree", "species_slug": "tea-tree", "varieties": [{"name": "Wild Type (Terpinen-4-ol Chemotype)", "slug": "wild-type-terpinen-4-ol-chemotype", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Northern NSW/Southeast Queensland, Australia (traditional Bundjalung lands)", "traits": "Small tree to 7m, bushy crown, narrow needle-like leaves 10-35mm, papery white bark", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Natural to swampy coastal Brisbane regions. Fast-growing in subtropical conditions, several feet per season. Excellent heat and humidity tolerance. Used traditionally by Indigenous Bundjalung people for medicine. Primary commercial tea tree oil source. Prefers moist soils near streams.", "availability": "Widely available in Queensland nurseries", "sort_order": 0}, {"name": "High Terpinen-4-ol Cultivars", "slug": "high-terpinen-4-ol-cultivars", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Australia, 1990s-present selection breeding", "traits": "Selected clones with 40-48% terpinen-4-ol, <5% cineole for pharmaceutical grade oil", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 1}, {"name": "Revolution Green", "slug": "revolution-green", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, modern cultivar selection", "traits": "Dense upright shrub/small tree 3-4m tall x 2-3m wide, vibrant needle-like green foliage year-round", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Perfect for Brisbane subtropical conditions. Tolerates heat, humidity, and coastal conditions. Drought-tolerant once established. Suitable for hedging, screens, ornamental gardens. Aromatic foliage when crushed.", "availability": "Widely available in Brisbane/Queensland nurseries", "sort_order": 2}, {"name": "Revolution Gold", "slug": "revolution-gold", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, modern cultivar selection", "traits": "Dense upright shrub 4m x 3m, attractive golden foliage (more intense in full sun)", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Excellent for Brisbane climate, thrives in subtropical heat and humidity. Color-contrast screening plant. Tolerates most soil types including clay and sandy loam. Fast-growing, responds well to pruning. Attracts native wildlife.", "availability": "Common in Queensland nurseries, garden centers", "sort_order": 3}, {"name": "Golden Gem", "slug": "golden-gem", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Australia, dwarf cultivar", "traits": "Compact dwarf form with golden foliage, smaller than Revolution Gold", "flesh_fruit": "", "yield_notes": "", "growing_notes": "", "availability": "", "sort_order": 4}, {"name": "Standard Form", "slug": "standard-form", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Queensland to NSW coast, also New Caledonia and PNG", "traits": "Medium-large tree 8-25m, thick white/cream papery bark, weeping branches. Leaves lanceolate to elliptic 40-70mm x 25mm, 5 prominent veins", "flesh_fruit": "", "yield_notes": "High flower production for nectar, traditional bark uses", "growing_notes": "Native to coastal Brisbane region (latitude 26°S). Extremely well-adapted to subtropical Queensland. Tolerates waterlogged to dry conditions. Frost-hardy to -5°C. Excellent for poorly drained sites, swampy areas. Bird-attracting. Aboriginal uses: bark for wrapping food, cradles, pillows, bandages.", "availability": "Common in Brisbane nurseries as landscape tree", "sort_order": 5}, {"name": "Red-flowered Form", "slug": "red-flowered-form", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Rare natural variant", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Same subtropical Brisbane tolerance as standard