y": "", "sort_order": 10}, {"name": "Wild Type", "slug": "wild-type", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "New Zealand, Tasmania, Victoria, NSW", "traits": "Shrub/small tree 2-5m (occasionally to 15m), prickly needle-like leaves 7-20mm", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Adaptable to Brisbane subtropical conditions. Frost-hardy to -10°C. Prefers well-drained acidic soils. Source of manuka honey. Māori traditional medicine uses.", "availability": "Available in Brisbane specialty nurseries", "sort_order": 11}, {"name": "Ruby Glow", "slug": "ruby-glow", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "Modern cultivar", "traits": "Compact upright shrub 180-240cm tall x 120-150cm wide, dark green needle-like leaves", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Suitable for Brisbane with protection. Zone 9-11. Aromatic foliage, drought-tolerant established. Excellent containers/borders.", "availability": "", "sort_order": 12}, {"name": "Red Damask", "slug": "red-damask", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "California breeding", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Dense medium shrub 1.8-2.5m. Suitable for Brisbane subtropical gardens.", "availability": "", "sort_order": 13}, {"name": "Apple Blossom", "slug": "apple-blossom", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "8ft tall and wide (240cm). Brisbane-suitable with good drainage.", "availability": "", "sort_order": 14}, {"name": "Burgundy Queen", "slug": "burgundy-queen", "lineage_type": "hybrid", "climate_slug": "humid-subtropical", "origin": "", "traits": "", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Upright dense shrub to 3.6m tall x 3m wide. Suitable for Brisbane landscapes.", "availability": "", "sort_order": 15}, {"name": "Helene Str