yield_notes": "Low culinary, high ornamental.", "growing_notes": "", "availability": "Specialty groundcover nurseries.", "sort_order": 17}, {"name": "Thymus pulegioides ''Foxley''", "slug": "thymus-pulegioides-foxley", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Selected for exceptional variegation.", "traits": "Larger rounded foliage than most thymes. Deep green leaves with cream variegation tinged pink. Highly ornamental. Upright 15-25cm.", "flesh_fruit": "", "yield_notes": "Moderate. Ornamental value high.", "growing_notes": "", "availability": "Specialty nurseries, rare plant suppliers.", "sort_order": 18}, {"name": "Thymus vulgaris", "slug": "thymus-vulgaris", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mediterranean. Not indigenous to Kerala.", "traits": "Upright growth 20-30cm. Gray-green leaves, pale flowers.", "flesh_fruit": "", "yield_notes": "Moderate in tropical conditions with proper management.", "growing_notes": "", "availability": "Limited availability in Kerala. Check Ayush Kerala (Thrissur online nursery), major Kerala garden centers, The Seed Store India online, import seeds from international suppliers.", "sort_order": 0}, {"name": "Thymus vulgaris (French cultivar)", "slug": "thymus-vulgaris-french-cultivar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "France/Mediterranean. Not indigenous to Kerala.", "traits": "Narrower leaves than English thyme. Compact 15-25cm. Reddish stems.", "flesh_fruit": "", "yield_notes": "Low in Kerala tropical conditions. High-maintenance.", "growing_notes": "", "availability": "Rare in Kerala. Special order from specialized nurseries or international seed companies.", "sort_order": 1}, {"name": "Thymus x citriodorus", "slug": "thymus-x-citriodorus", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Mediterranean hybrid. Not indigenous to Kerala.", "traits": "Small shrub 15-30cm. Oval dark green leaves. Pink/lavender flowers. Citrus scent.", "flesh_fruit": "", "yield_notes": "Moderate with intensive care in Kerala.", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Thymus vulgaris (German cultivar)", "slug": "thymus-vulgaris-german-cultivar", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Germany. Selected for hardiness. Not indigenous to Kerala.", "traits": "Small evergreen leaves, rounded. Compact 15-20cm. Robust.", "flesh_fruit": "", "yield_notes": "BEST YIELD among thymes for Kerala conditions.", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Thymus serpyllum / T. praecox", "slug": "thymus-serpyllum-t-praecox", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Europe. Ancient heirloom. Not indigenous to Kerala.", "traits": "Very low mat-forming groundcover 2-8cm. Tiny leaves. Profuse flowers.", "flesh_fruit": "", "yield_notes": "Very poor in Kerala monsoon.", "growing_notes": "", "availability": "Very limited in Kerala. Not recommended to pursue.", "sort_order": 4}, {"name": "Thymus pseudolanuginosus", "slug": "thymus-pseudolanuginosus", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Selected variegated cultivars. Not indigenous to Kerala.", "traits": "Variegated silver-green or white-edged foliage. Various sizes.", "flesh_fruit": "", "yield_notes": "Low to moderate with intensive management.", "growing_notes": "", "availability": "Not available and not suitable for Kerala.", "sort_order": 5}, {"name": "Thymus x citriodorus ''Lime'' / T. vulgaris ''Orange Balsam''", "slug": "thymus-x-citriodorus-lime-t-vulgaris-orange-balsam", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Cultivar selections. Not indigenous to Kerala.", "traits": "Citrus-scented varieties. Compact growth.", "flesh_fruit": "", "yield_notes": "Poor to moderate in Kerala.", "growing_notes": "", "availability": "Rare in Kerala. Special order from specialty suppliers or international sources.", "sort_order": 6}, {"name": "Thymus herba-barona", "slug": "thymus-herba-barona", "lineage_type": "open_pollinated", "climate_slug": "tropical-monsoon", "origin": "Sardinia/Corsica. Not indigenous to Kerala.", "traits": "Low-growing 10-15cm. Narrow dark green leaves. Caraway scent.", "flesh_fruit": "", "yield_notes": "Moderate potential in Kerala with care.", "growing_notes": "", "availability": "Very limited in Kerala. International seed suppliers.", "sort_order": 7}, {"name": "Thymus pulegioides cv. Pennsylvania Dutch", "slug": "thymus-pulegioides-cv-pennsylvania-dutch", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "Pennsylvania Dutch heritage, USA. Not indigenous to Kerala.", "traits": "Larger oval leaves. Upright 30cm. Strong scent.", "flesh_fruit": "", "yield_notes": "Good potential for Kerala - larger leaves.", "growing_notes": "", "availability": "", "sort_order": 8}], "variety_count": 28}'::jsonb,
