UPDATE public.garden_import_queue SET payload = '{"species": "Tomatillo", "species_slug": "tomatillo", "varieties": [{"name": "Toma Verde", "slug": "toma-verde", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico, traditional variety", "traits": "Golf-ball sized (2\" diameter), bright green when young, turns pale golden-green when ripe. Papery tan husks. Plants 3-4 feet tall, bushy spreading habit.", "flesh_fruit": "Firm, sweet-tart flavor like lemon-pineapple-tomato cross. Tangy and citrusy. Sticky coating when fresh.", "yield_notes": "Very productive, 60-70 days maturity. Early maturing, prolific bearer.", "growing_notes": "", "availability": "The Seed Collection (Victoria, AU), Mr Fothergill''s Australia, Local Seeds Australia, widely available", "sort_order": 0}, {"name": "Verde Puebla", "slug": "verde-puebla", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Puebla, Mexico", "traits": "3-5cm diameter fruit, larger and more yellow-green than Toma Verde. Papery husks that dry and flake when ripe.", "flesh_fruit": "Sweet/tart balanced flavor. Essential for authentic Mexican salsa verde. Full of flavor.", "yield_notes": "Reliable producer, 70 days to harvest", "growing_notes": "", "availability": "Happy Valley Seeds Australia, The Seed Collection Australia", "sort_order": 1}, {"name": "Rio Grande Verde", "slug": "rio-grande-verde", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Mexico/Rio Grande region", "traits": "LARGE apple-green fruits, 2-3\" diameter (1.8-2.8 oz, up to 4 oz). Compact determinate plants 2-3 feet tall, medium-sized, no staking needed.", "flesh_fruit": "Sweet and tangy, bright apple-green color. Sweet green pepper mixed with tomato flavor. Excellent for salsa verde.", "yield_notes": "Very high yields, quick maturing (80-85 days). Prolific producer.", "growing_notes": "", "availability": "Available from various Australian seed suppliers", "sort_order": 2}, {"name": "Purple Tomatillo", "slug": "purple-tomatillo", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mexico, heirloom variety", "traits": "Small-medium size (1.5-2\" diameter), electric violet/deep purple color where exposed to sun. Golf ball shape, bushy plants 20-36\" tall.", "flesh_fruit": "Sweet-tart flavor, sweeter than green varieties. Citrus notes of lemon with plum/pear sub-acid flavors. Less sticky than green types. Clear, delicate flesh.", "yield_notes": "Prolific, 90 days maturity. Very productive.", "growing_notes": "", "availability": "Specialty seed suppliers, some Australian online retailers", "sort_order": 3}, {"name": "Purple Coban", "slug": "purple-coban", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Cobán, Guatemala (mountain town) - collected heirloom", "traits": "Small fruits 1\" diameter, green with dark purple hue that deepens at maturity. Compact plants.", "flesh_fruit": "Sweet, distinctive tomatillo flavor with citrus notes. Excellent for colorful salsas.", "yield_notes": "Good yields, 70-80 days maturity", "growing_notes": "", "availability": "Specialty heirloom seed suppliers, may require import", "sort_order": 4}, {"name": "Purple de Milpa", "slug": "purple-de-milpa", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Mexico - grows wild in Mexican cornfields (milpas), ancient heirloom", "traits": "Very small fruits (¾\" diameter), purple-tinged green. Plants 3-4 feet tall. Wild-type characteristics.", "flesh_fruit": "Sharp, pronounced flavor preferred by some cooks. More intense than cultivated varieties. Mottled purple-green coloring.", "yield_notes": "70-90 days. Fruit typically doesn''t burst through husk when ripe.", "growing_notes": "", "availability": "Specialty heirloom suppliers, Baker Creek-type seed companies", "sort_order": 5}, {"name": "Gigante (Giant Green)", "slug": "gigante-giant-green", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Bred variety, developed for size", "traits": "LARGEST tomatillo variety - fruits 4\" across (up to 10cm). Bright green. Sprawling indeterminate plants can reach 4 feet tall. Needs cages or staking.", "flesh_fruit": "Sweeter than most varieties (50% more sugar than standard types). Excellent flavor for salsa, soups, Latin dishes.", "yield_notes": "Very high productivity, 100 days maturity. Fruit falls when ripe.", "growing_notes": "", "availability": "Burpee (may ship to Australia), specialty seed suppliers", "sort_order": 6}, {"name": "Amarylla (Yellow Tomatillo)", "slug": "amarylla-yellow-tomatillo", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "origin": "Poland - bred for cooler climates", "traits": "Golden-yellow fruits with peach-colored husks. Standard size. Cool-climate adapted.", "flesh_fruit": "SWEET rather than tart - unusual for tomatillos. Good for jams, jellies, preserves, fresh snacking. Sweet enough to use in cakes.", "yield_notes": "Good production, 60 days (very early maturity)", "growing_notes": "", "availability": "Specialty suppliers, may require import from Northern Hemisphere", "sort_order": 7}, {"name": "Pineapple Tomatillo (Ground Cherry type)", "slug": "pineapple-tomatillo-ground-cherry-type", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Heirloom variety, sometimes classified as ground cherry (Physalis pruinosa)", "traits": "Small cherry-sized fruits, golden-yellow when ripe. Compact vining plants 18\" tall. Yellow-gold fruit in papery husks.", "flesh_fruit": "Fruity pineapple flavor - sweet and tangy. Can be eaten green to yellow. Flavor improves as it ripens. Less tart than standard tomatillos.", "yield_notes": "75 days maturity, productive for size", "growing_notes": "", "availability": "Specialty seed companies, heirloom suppliers", "sort_order": 8}, {"name": "Mexican Strain", "slug": "mexican-strain", "lineage_type": "open_pollina