UPDATE public.garden_import_queue SET payload = '{"species": "Viola", "species_slug": "viola", "varieties": [{"name": "Viola banksii (Native Violet) 🌏 INDIGENOUS", "slug": "viola-banksii-native-violet-indigenous", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Native to east coast Australia, near Brisbane to Batemans Bay, named after Joseph Banks who collected specimens at Botany Bay in 1770", "traits": "Prostrate groundcover, spreading by layering stems, kidney-shaped bright green leaves 15-25mm diameter", "flesh_fruit": "", "yield_notes": "Prolific flowering, can spread to cover very large areas in moist positions", "growing_notes": "Exceptionally well-adapted to Brisbane subtropical climate. Hardy in range of conditions. Prefers moist, sunny to semi-shaded locations. Tolerates Brisbane heat better than exotic species. Ideal as groundcover, in containers, or hanging baskets. Formerly known as V. hederacea.", "availability": "Widely available: Australian Plants Online, Sunshine Coast Plants, Daleys Fruit Tree Nursery, The Plant Hub (ships to Brisbane), Plantmark Wholesale Nursery", "sort_order": 0}, {"name": "Viola hederacea (Native Violet) 🌏 INDIGENOUS", "slug": "viola-hederacea-native-violet-indigenous", "lineage_type": "indigenous", "climate_slug": "humid-subtropical", "origin": "Tasmania and southern regions (true V. hederacea, as revised by Kevin Thiele 2003-2004)", "traits": "Low-growing evergreen, circular heart-shaped leaves, forms dense mat, 5-15cm height, spreading to 2m width", "flesh_fruit": "", "yield_notes": "Dense flowering carpet, prolific bloomer", "growing_notes": "Suitable for Brisbane with adequate moisture. Prefers partial to full shade. Adaptable to various soil types. Excellent for shady spots, between pavers, lawn alternative in shade. Fast-spreading groundcover. Requires regular water in hot, dry weather.", "availability": "Queensland nurseries, Sunshine Coast Plants (delivers Brisbane), Daleys Fruit Tree", "sort_order": 1}, {"name": "Swiss Giants Mix 🏆 HEIRLOOM", "slug": "swiss-giants-mix-heirloom", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Developed 1800s, crossing Viola lutea, V. tricolor, and V. altaica. Named for Swedish botanist Veit Brecher Wittrock", "traits": "Large flowers 6-8cm (2.5-3.5 inches), compact growth 15-20cm tall, mounding habit", "flesh_fruit": "", "yield_notes": "Prolific bloomer in cool weather", "growing_notes": "", "availability": "", "sort_order": 2}, {"name": "Johnny Jump Up (Viola tricolor) 🏆 HEIRLOOM", "slug": "johnny-jump-up-viola-tricolor-heirloom", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "European wildflower (heartsease), naturalized worldwide. Progenitor of modern pansies", "traits": "Compact 10-15cm tall, spreading habit, self-sows freely. Smaller than modern pansies", "flesh_fruit": "", "yield_notes": "Extremely prolific, self-sowing annual/perennial", "growing_notes": "", "availability": "", "sort_order": 3}, {"name": "Victorian Posy 🏆 HEIRLOOM", "slug": "victorian-posy-heirloom", "lineage_type": "heirloom", "climate_slug": "humid-subtropical", "origin": "Modern breeding for early flowering and cold tolerance", "traits": "Uniform habit, compact plants, early blooming", "flesh_fruit": "", "yield_notes": "Early and reliable flowering", "growing_notes": "Nostalgic Victorian-style flowers. Best for Brisbane winter season. Plant autumn for winter-spring blooms. Excellent for containers and borders. Heat-sensitive. EXCELLENT FOR BRISBANE. Among the most heat-tolerant pansies available. Outstanding performance in subtropical conditions. Rebounds well from extreme weather. Suitable for Brisbane autumn-spring planting with extended season. Modern breeding provides disease resistance. Most cold-hardy pansy (hardy to zone 5). Excellent for Brisbane hanging baskets and containers. Trailing habit ideal for vertical displays. Good performance autumn-spring in Brisbane. Heat will limit summer survival. Popular for Brisbane winter gardens. Plant autumn for winter-spring display. Excellent for borders, containers. Declines in summer heat. Edible flowers for garnishes. Bred for unpredictable spring weather, suitable for Brisbane winter season. Good performance in cool conditions.", "availability": "Major commercial seed suppliers", "sort_order": 4}, {"name": "Viola serpens (syn. Viola pilosa) 🌏 INDIGENOUS", "slug": "viola-serpens-syn-viola-pilosa-indigenous", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Himalayan region of India, Pakistan, Nepal, China, also found in Java, Philippines, Thailand, Ceylon", "traits": "Herbaceous perennial, prostrate stems to 100cm rooting at nodes, rosette of leaves. Variable species", "flesh_fruit": "", "yield_notes": "", "growing_notes": "COOLER ELEVATIONS ONLY in Kerala. Traditional medicinal plant. Prefers shady, moist environments. Grows wild in hill regions at 1500-2000m altitude. Not suitable for Kerala lowland tropical heat.", "availability": "Wild collection from hills, specialized medicinal plant nurseries in India, conservation status: declining due to overexploitation", "sort_order": 0}, {"name": "Viola canescens (Himalayan White Violet) 🌏 INDIGENOUS", "slug": "viola-canescens-himalayan-white-violet-indigenous", "lineage_type": "indigenous", "climate_slug": "tropical-monsoon", "origin": "Native to Europe, Western Asia, naturalized in parts of India at higher altitudes (1500-1800m)", "traits": "Herbaceous perennial, stoloniferous (spreads by runners), heart-shaped leaves 6cm long, 10-15cm height", "flesh_fruit": "", "yield_notes": "", "growing_notes": "COOLER ELEVATIONS ONLY. Cold desert and Himalayan species, requires cool temperatures. Endangered status due to overexploitation. NOT suitable for Kerala tropical lowlands. Potentially in Kerala hill stations above 1500m.", "availability": "Conservation concern - endangered. Specialized Indian botanical gardens, medicinal plant nurseries", "sort_order": 1}, {"name": "Viola tricolor (Heartsease, Wild Pansy) 🏆 HEIRLOOM", "slug": "viola-tricolor-heartsease-wild-pansy-heirloom", "lineage_type": "heirloom", "climate_slug": "tropical-monsoon", "origin": "European wildflower, cultivated in India as ornamental, occasionally escapes", "traits": "Annual/short-lived perennial, 7-25cm tall", "flesh_fruit": "", "yield_notes": "", "growing_notes": "Cultivated as ornamental in Indian gardens but not well-adapted to Kerala tropical heat. May survive in cooler microclimates. Flowering November-May in India.", "availability": "Indian seed companies for ornamental use, limited availability", "sort_order": 2}], "variety_count": 8}'::jsonb,
